def _dump_billing_account(values: BillingAccountCreate | BillingAccountUpdate) -> dict[str, Any]:
    data = values.model_dump(exclude_unset=True)
    if "metadata" in data:
        data["metadata_"] = data.pop("metadata")
    return data

